2459 static bool deduceFunctionAttributeInRPO(Module &M, LazyCallGraph &CG) {
2460   // We only have a post-order SCC traversal (because SCCs are inherently
2461   // discovered in post-order), so we accumulate them in a vector and then walk
2462   // it in reverse. This is simpler than using the RPO iterator infrastructure
2463   // because we need to combine SCC detection and the PO walk of the call
2464   // graph. We can also cheat egregiously because we're primarily interested in
2465   // synthesizing norecurse and so we can only save the singular SCCs as SCCs
2466   // with multiple functions in them will clearly be recursive.
2467 
2468   SmallVector<Function *, 16> Worklist;
2469   CG.buildRefSCCs();
2470   for (LazyCallGraph::RefSCC &RC : CG.postorder_ref_sccs()) {
2471     for (LazyCallGraph::SCC &SCC : RC) {
2472       if (SCC.size() != 1)
2473         continue;
2474       Function &F = SCC.begin()->getFunction();
2475       if (!F.isDeclaration() && F.hasInternalLinkage() && !F.use_empty())
2476         Worklist.push_back(&F);
2477     }
2478   }
2479   bool Changed = false;
2480   for (auto *F : llvm::reverse(Worklist)) {
2481     Changed |= addNoRecurseAttrsTopDown(*F);
2482     Changed |= addNoFPClassAttrsTopDown(*F);
2483   }
2484 
2485   return Changed;
2486 }
