2410 static bool addNoFPClassAttrsTopDown(Function &F) {
2411   assert(!F.isDeclaration() && "Cannot deduce nofpclass without a definition!");
2412   unsigned NumArgs = F.arg_size();
2413   SmallVector<FPClassTest, 8> ArgsNoFPClass(NumArgs, fcAllFlags);
2414   FPClassTest RetNoFPClass = fcAllFlags;
2415 
2416   bool Changed = false;
2417   for (User *U : F.users()) {
2418     auto *CB = dyn_cast<CallBase>(U);
2419     if (!CB || CB->getCalledFunction() != &F)
2420       return false;
2421 
2422     RetNoFPClass &= CB->getRetNoFPClass();
2423     for (unsigned I = 0; I != NumArgs; ++I) {
2424       // TODO: Consider computeKnownFPClass, at least with a small search
2425       // depth. This will currently not catch non-splat vectors.
2426       const APFloat *Cst;
2427       if (match(CB->getArgOperand(I), m_APFloat(Cst)))
2428         ArgsNoFPClass[I] &= ~Cst->classify();
2429       else
2430         ArgsNoFPClass[I] &= CB->getParamNoFPClass(I);
2431     }
2432   }
2433 
2434   LLVMContext &Ctx = F.getContext();
2435 
2436   if (RetNoFPClass != fcNone) {
2437     FPClassTest OldAttr = F.getAttributes().getRetNoFPClass();
2438     if (OldAttr != RetNoFPClass) {
2439       F.addRetAttr(Attribute::getWithNoFPClass(Ctx, RetNoFPClass));
2440       Changed = true;
2441     }
2442   }
2443 
2444   for (unsigned I = 0; I != NumArgs; ++I) {
2445     FPClassTest ArgNoFPClass = ArgsNoFPClass[I];
2446     if (ArgNoFPClass == fcNone)
2447       continue;
2448     FPClassTest OldAttr = F.getParamNoFPClass(I);
2449     if (OldAttr == ArgNoFPClass)
2450       continue;
2451 
2452     F.addParamAttr(I, Attribute::getWithNoFPClass(Ctx, ArgNoFPClass));
2453     Changed = true;
2454   }
2455 
2456   return Changed;
2457 }
