2488 PreservedAnalyses
2489 ReversePostOrderFunctionAttrsPass::run(Module &M, ModuleAnalysisManager &AM) {
2490   auto &CG = AM.getResult<LazyCallGraphAnalysis>(M);
2491 
2492   if (!deduceFunctionAttributeInRPO(M, CG))
2493     return PreservedAnalyses::all();
2494 
2495   PreservedAnalyses PA;
2496   PA.preserve<LazyCallGraphAnalysis>();
2497   return PA;
2498 }
