337 template <int64_t Val> struct constantint_match {
338   template <typename ITy> bool match(ITy *V) const {
339     if (const auto *CI = dyn_cast<ConstantInt>(V)) {
340       const APInt &CIV = CI->getValue();
341       if (Val >= 0)
